function GUIManager:addLayout(layout, parent)
    if not parent or parent == RootWindow then
        Layouts[layout.__name] = layout
    else
        SubLayouts[layout.__name] = layout
    end
    parent = parent or RootWindow
    parent:AddChildWindow(layout.root)
end

function GUIManager:removeLayout(layout)
    Layouts[layout.__name] = nil
    SubLayouts[layout.__name] = nil
end

