function GUIManager:onTick(frameTime)
    for name, layout in pairs(Layouts) do
        if layout:isShow() then
            layout:onTick(frameTime)
        end
    end
    for name, layout in pairs(SubLayouts) do
        if layout:isShow() then
            layout:onTick(frameTime)
        end
    end
    if #ShowQueue > 0 then
        local item = ShowQueue[1]
        if item.tag == false then
            if not GuideWindow:IsVisible() then
                item.layout:show()
                item.tag = true
            end
        else
            if not item.layout:isShow() then
                table.remove(ShowQueue, 1)
            end
        end
    end
end

